<!doctype html><html lang="zh-CN"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>DepartmentIFO</title><script src="/DepartmentIFO/auth-monitor/sdk/js/auth-monitor.min.js"></script><style>
:root{--bg:#f4f7fb;--panel:#fff;--text:#172033;--muted:#667085;--line:#d9e2ef;--brand:#0f766e;--blue:#2563eb;--danger:#dc2626;--ok:#15803d;--side:#101828;--shadow:0 14px 35px rgba(15,23,42,.10)}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font-family:Arial,"Microsoft YaHei",sans-serif}button,a,input,select,textarea{font-family:inherit}.login-page{min-height:100vh;display:grid;grid-template-columns:1.12fr .88fr;background:#0b1220}.login-visual{padding:58px;color:white;display:flex;flex-direction:column;justify-content:space-between;background:radial-gradient(circle at 20% 15%,rgba(45,212,191,.28),transparent 28%),linear-gradient(135deg,#0f766e,#1d4ed8 62%,#101828)}.login-visual h1{font-size:44px;margin:0 0 16px}.login-visual p{font-size:17px;line-height:1.85;color:#e8f2ff;max-width:640px}.login-stats{display:grid;grid-template-columns:repeat(3,1fr);gap:14px}.login-stat{border:1px solid rgba(255,255,255,.28);padding:18px;border-radius:8px;background:rgba(255,255,255,.1);backdrop-filter:blur(10px);transition:.22s}.login-stat:hover{transform:translateY(-3px);box-shadow:0 18px 35px rgba(0,0,0,.22)}.login-stat b{display:block;font-size:28px}.login-box{background:white;display:flex;align-items:center;justify-content:center;padding:32px}.login-card{width:min(430px,100%);animation:rise .45s ease}.login-card h2{font-size:29px;margin:0 0 8px}.hint{color:var(--muted);line-height:1.7}.field{margin-bottom:14px}.field label{display:block;font-weight:700;margin-bottom:7px}.field input,.field select,.field textarea{width:100%;padding:12px;border:1px solid var(--line);border-radius:6px;font-size:14px;background:white;transition:.18s}.field input:focus,.field select:focus,.field textarea:focus{outline:0;border-color:var(--blue);box-shadow:0 0 0 3px rgba(37,99,235,.12)}.btn{border:0;border-radius:6px;padding:10px 14px;background:var(--blue);color:white;cursor:pointer;font-weight:700;transition:.16s;text-decoration:none;display:inline-block}.btn:hover{transform:translateY(-1px);box-shadow:0 8px 20px rgba(37,99,235,.22)}.btn:active{transform:scale(.98)}.btn.secondary{background:#eef4ff;color:#1d4ed8}.btn.danger{background:#fee2e2;color:#b91c1c}.btn.ok{background:#dcfce7;color:#166534}.btn.ghost{background:transparent;color:#475467;border:1px solid var(--line)}.btn.block{width:100%;font-size:15px}.err{color:#b91c1c;min-height:22px}.app{display:grid;grid-template-columns:260px 1fr;min-height:100vh;transition:.2s}.app.collapsed{grid-template-columns:76px 1fr}.side{background:var(--side);color:white;padding:18px 12px;overflow:hidden}.brand{display:flex;align-items:center;gap:10px;font-size:18px;font-weight:800;padding:8px 8px 20px;white-space:nowrap}.logo{width:36px;height:36px;border-radius:8px;background:linear-gradient(135deg,var(--brand),var(--blue));display:grid;place-items:center}.collapse{margin-left:auto;background:#1f2937;border:0;color:#fff;border-radius:6px;padding:7px;cursor:pointer}.nav button{width:100%;display:flex;align-items:center;gap:10px;border:0;background:transparent;color:#cbd5e1;padding:12px 10px;border-radius:6px;cursor:pointer;text-align:left;font-size:14px;margin:3px 0;transition:.16s}.nav button:hover,.nav button.active{background:#1e293b;color:#fff;transform:translateX(2px)}.app.collapsed .nav span,.app.collapsed .brand span{display:none}.main{min-width:0}.top{height:64px;background:white;border-bottom:1px solid var(--line);display:flex;align-items:center;justify-content:space-between;padding:0 24px;position:sticky;top:0;z-index:5}.top h2{margin:0;font-size:18px}.content{padding:22px}.cards{display:grid;grid-template-columns:repeat(5,minmax(140px,1fr));gap:14px;margin-bottom:16px}.card{background:var(--panel);border:1px solid var(--line);border-radius:8px;padding:16px;transition:.2s;animation:fade .24s ease}.card:hover{box-shadow:var(--shadow);transform:translateY(-2px)}.label{color:var(--muted);font-size:13px}.num{font-size:30px;font-weight:800;margin-top:8px}.grid2{display:grid;grid-template-columns:1.2fr .8fr;gap:16px}.toolbar{display:flex;gap:10px;flex-wrap:wrap;align-items:center;margin-bottom:12px}.toolbar input,.toolbar select{padding:10px;border:1px solid var(--line);border-radius:6px}.table-wrap{overflow:auto;border-radius:8px;border:1px solid var(--line);background:white}table{width:100%;border-collapse:collapse;background:white}th,td{border-bottom:1px solid #edf2f7;padding:11px;text-align:left;font-size:14px;white-space:nowrap}th{background:#f8fafc;color:#475467}.pill{display:inline-block;border-radius:999px;padding:4px 9px;font-size:12px;background:#eef2ff;color:#3730a3}.pill.ok{background:#dcfce7;color:#166534}.pill.off{background:#fee2e2;color:#991b1b}.pill.warn{background:#fef3c7;color:#92400e}.section-title{display:flex;justify-content:space-between;align-items:center;margin-bottom:12px}.section-title h3{margin:0}.org-grid{display:grid;grid-template-columns:repeat(2,minmax(260px,1fr));gap:14px}.dept{background:white;border:1px solid var(--line);border-left:4px solid var(--brand);border-radius:8px;padding:15px;transition:.2s}.dept:hover{box-shadow:var(--shadow);transform:translateY(-2px)}.people{display:flex;flex-wrap:wrap;gap:8px;margin-top:12px}.person{padding:7px 9px;border-radius:6px;background:#f8fafc;border:1px solid #e5e7eb;cursor:pointer}.person:hover{background:#eef6ff}.score{height:8px;background:#e5e7eb;border-radius:999px;overflow:hidden}.score span{display:block;height:100%;background:linear-gradient(90deg,var(--brand),var(--blue))}.pager{display:flex;gap:8px;justify-content:flex-end;margin-top:12px}.modal{position:fixed;inset:0;background:rgba(15,23,42,.45);display:none;align-items:center;justify-content:center;padding:20px;z-index:20}.modal.show{display:flex}.modal-card{background:white;border-radius:8px;width:min(860px,100%);max-height:88vh;overflow:auto;padding:22px;animation:pop .18s ease;box-shadow:0 22px 60px rgba(0,0,0,.22)}.form-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:12px}.empty{color:var(--muted);padding:20px;text-align:center}@keyframes rise{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:none}}@keyframes fade{from{opacity:.5;transform:translateY(4px)}to{opacity:1;transform:none}}@keyframes pop{from{opacity:0;transform:scale(.96)}to{opacity:1;transform:scale(1)}}@media(max-width:980px){.login-page{grid-template-columns:1fr}.app,.app.collapsed{grid-template-columns:1fr}.side{position:sticky;top:0;z-index:10}.nav{display:grid;grid-template-columns:repeat(3,1fr);gap:4px}.cards{grid-template-columns:repeat(2,1fr)}.grid2,.org-grid{grid-template-columns:1fr}.collapse{display:none}}@media(max-width:620px){.content{padding:14px}.cards,.form-grid{grid-template-columns:1fr}.login-visual{padding:32px}.login-visual h1{font-size:30px}.login-stats{grid-template-columns:1fr}}
</style></head><body><div id="root"></div><div id="modal" class="modal" onclick="if(event.target.id==='modal')closeModal()"><div class="modal-card" id="modalCard"></div></div><script>
AuthMonitor.init({appId:'member-platform',apiBase:'/DepartmentIFO/auth-monitor/api/v1',autoTrack:true});
const T={title:'\u90e8\u95e8\u6210\u5458\u7ba1\u7406\u5e73\u53f0',sub:'\u9762\u5411\u90e8\u95e8\u7ba1\u7406\u7684\u7ec4\u7ec7\u3001\u6863\u6848\u3001\u8003\u6838\u3001\u6388\u6743\u4e0e\u76d1\u63a7\u4e2d\u5fc3',login:'\u767b\u5f55',account:'\u5b66\u53f7 / \u8d26\u53f7',password:'\u5bc6\u7801',dashboard:'\u6570\u636e\u770b\u677f',members:'\u6210\u5458\u6863\u6848',org:'\u7ec4\u7ec7\u67b6\u6784',eval:'\u8003\u6838\u8bc4\u4ef7',approval:'\u5ba1\u6279\u4e2d\u5fc3',imports:'\u6279\u91cf\u5bfc\u5165',audit:'\u64cd\u4f5c\u65e5\u5fd7',perm:'\u6743\u9650\u6388\u6743',logout:'\u9000\u51fa'};
let token=localStorage.getItem('mp_token'),me=null,state={page:'dashboard',collapsed:false,pageNo:1,limit:20,total:0,members:[],perms:[]};
function has(p){return state.perms.includes('*')||state.perms.includes(p)}function root(){return document.getElementById('root')}function esc(s){return String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]))}function api(path,opt={}){opt.headers=Object.assign({'Content-Type':'application/json','Authorization':'Bearer '+token},opt.headers||{});return fetch('/DepartmentIFO/member-platform/api'+path,opt).then(r=>r.json())}function statusLabel(s){return {active:'??',suspended:'??',retired:'??',trial:'??',left:'??',graduated:'??',disabled:'??'}[s]||s}function pill(s){let cls=s==='active'?'ok':s==='suspended'?'warn':'off';return `<span class="pill ${cls}">${statusLabel(s)}</span>`}
function renderLogin(){root().innerHTML=`<div class="login-page"><section class="login-visual"><div><h1>${T.title}</h1><p>${T.sub}</p></div><div class="login-stats"><div class="login-stat"><b>Auth</b><span>????</span></div><div class="login-stat"><b>Org</b><span>???</span></div><div class="login-stat"><b>360</b><span>????</span></div></div></section><section class="login-box"><div class="login-card"><h2>${T.login}</h2><p class="hint">????????????????????????????????</p><div class="field"><label>${T.account}</label><input id="u" autocomplete="username"></div><div class="field"><label>${T.password}</label><input id="p" type="password" autocomplete="current-password"></div><button class="btn block" onclick="loginNow()">${T.login}</button><p class="err" id="loginMsg"></p></div></section></div>`}
function loginNow(){fetch('/DepartmentIFO/member-platform/api/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({username:u.value,password:p.value})}).then(r=>r.json()).then(d=>{if(d.ok){token=d.access_token;localStorage.setItem('mp_token',token);AuthMonitor.setToken(token);boot()}else loginMsg.textContent=d.message||'????'})}
function boot(){api('/me').then(d=>{if(!d.ok){localStorage.removeItem('mp_token');return renderLogin()}me=d;state.perms=d.permissions||[];shell()})}function logoutNow(){localStorage.removeItem('mp_token');location.reload()}function navs(){let all=[['dashboard',T.dashboard,'dashboard.view'],['members',T.members,'members.view'],['org',T.org,'organization.view'],['eval',T.eval,'evaluations.view'],['approval',T.approval,'dashboard.view'],['imports',T.imports,'imports.view'],['perm',T.perm,'permissions.grant'],['audit',T.audit,'audit.view']];return all.filter(x=>has(x[2])||has('*')||(x[0]==='members'&&has('members.self'))||(x[0]==='eval'&&has('evaluations.self')))}
function shell(){let ns=navs();if(!ns.find(x=>x[0]===state.page))state.page=ns[0]?.[0]||'dashboard';root().innerHTML=`<div class="app ${state.collapsed?'collapsed':''}"><aside class="side"><div class="brand"><div class="logo">D</div><span>DepartmentIFO</span><button class="collapse" onclick="toggleSide()">?</button></div><nav class="nav">${ns.map(x=>`<button class="${state.page===x[0]?'active':''}" onclick="go('${x[0]}')"><b>?</b><span>${x[1]}</span></button>`).join('')}</nav></aside><main class="main"><div class="top"><h2>${pageTitle()}</h2><div><span class="pill ok">${esc(me.user.name||me.user.username)}</span> <button class="btn secondary" onclick="logoutNow()">${T.logout}</button></div></div><div class="content" id="content"></div></main></div>`;loadPage()}function toggleSide(){state.collapsed=!state.collapsed;shell()}function pageTitle(){return {dashboard:T.dashboard,members:T.members,org:T.org,eval:T.eval,approval:T.approval,imports:T.imports,audit:T.audit,perm:T.perm}[state.page]||T.dashboard}function go(p){state.page=p;state.pageNo=1;shell()}function loadPage(){({dashboard:loadDashboard,members:loadMembers,org:loadOrg,eval:loadEval,approval:loadApprovals,imports:loadImports,audit:loadAudit,perm:loadPerm}[state.page]||loadDashboard)()}
function loadDashboard(){api('/dashboard/overview').then(d=>{content.innerHTML=`<div class="cards"><div class="card"><div class="label">????</div><div class="num">${d.total}</div></div><div class="card"><div class="label">??</div><div class="num">${d.active}</div></div><div class="card"><div class="label">??</div><div class="num">${d.retired}</div></div><div class="card"><div class="label">??</div><div class="num">${d.suspended}</div></div><div class="card"><div class="label">????</div><div class="num">${d.avg_score}</div></div></div><div class="grid2"><div class="card"><h3>?????????</h3>${(d.departments||[]).map(x=>`<p>${esc(x.name)} <span class="pill">? ${x.c}</span> <span class="pill ok">?? ${x.active_count||0}</span></p><div class="score"><span style="width:${Math.min(100,(x.c/d.total)*100||0)}%"></span></div>`).join('')}</div><div class="card"><h3>????</h3>${(d.recent||[]).map(x=>`<p><b>${esc(x.actor)}</b> ${esc(x.action)}<br><span class="label">${x.created_at}</span></p>`).join('')||'<div class="empty">????</div>'}</div></div>`})}
function memberParams(){return `page=${state.pageNo}&limit=${state.limit}&status=${document.getElementById('sf')?.value||'active'}&q=${encodeURIComponent(document.getElementById('q')?.value||'')}`}function loadMembers(){api('/members?'+memberParams()).then(d=>{state.members=d.data||[];state.total=d.total||0;content.innerHTML=`<div class="toolbar"><input id="q" placeholder="????/??/??/??"><select id="sf"><option value="active">????</option><option value="retired">????</option><option value="suspended">????</option><option value="all">????</option></select><button class="btn" onclick="state.pageNo=1;loadMembers()">??</button>${has('members.sensitive')||has('*')?'<button class="btn secondary" onclick="openMemberForm()">????</button>':''}<a class="btn secondary" href="/DepartmentIFO/member-platform/api/export/members" target="_blank">??</a></div><div class="table-wrap"><table><thead><tr><th>??</th><th>??</th><th>??</th><th>??</th><th>??</th><th>??</th></tr></thead><tbody>${state.members.map(m=>`<tr><td><a href="javascript:viewMember(${m.id})">${esc(m.name)}</a></td><td>${esc(m.stuno)}</td><td>${esc(m.bm)}</td><td>${esc(m.posts)}</td><td>${pill(m.status)}</td><td><button class="btn secondary" onclick="viewMember(${m.id})">??</button> ${has('members.status')||has('*')?`<button class="btn danger" onclick="setStatus(${m.id},'suspend')">??</button><button class="btn ghost" onclick="setStatus(${m.id},'retire')">??</button><button class="btn ok" onclick="setStatus(${m.id},'restore')">??</button>`:''}</td></tr>`).join('')}</tbody></table></div><div class="pager"><span>? ${state.pageNo} ? / ? ${state.total} ?</span><button class="btn secondary" onclick="state.pageNo=Math.max(1,state.pageNo-1);loadMembers()">???</button><button class="btn secondary" onclick="state.pageNo++;loadMembers()">???</button></div>`})}function setStatus(id,a){api('/members/'+id+'/'+a,{method:'POST',body:'{}'}).then(loadMembers)}
function viewMember(id){api('/members/'+id).then(d=>{if(!d.ok)return alert(d.message);let m=d.member;modal(`<h3>${esc(m.name)} ?????</h3><div class="cards"><div class="card"><div class="label">??</div><b>${esc(m.stuno)}</b></div><div class="card"><div class="label">??</div><b>${esc(m.bm)}</b></div><div class="card"><div class="label">??</div><b>${esc(m.posts)}</b></div><div class="card"><div class="label">??</div>${pill(m.status)}</div></div><div class="grid2"><div class="card"><h3>????</h3><p>???${esc(m.phone)}</p><p>???${esc(m.email)}</p><p>???${esc(m.tags)}</p><p>???${esc(m.remark)}</p></div><div class="card"><h3>????</h3><p>${esc(d.profile?.training_record||'??????')}</p></div></div><div class="card"><h3>????</h3>${(d.evaluations||[]).map(e=>`<p>${e.created_at}?${e.total_score} ??${esc(e.level)}?${esc(e.comment)}</p>`).join('')||'??????'}</div><button class="btn secondary" onclick="closeModal()">??</button>`)} )}
function openMemberForm(){modal(`<h3>????</h3><div class="form-grid"><div class="field"><label>??</label><input id="mn"></div><div class="field"><label>??</label><input id="ms"></div><div class="field"><label>??</label><input id="mb"></div><div class="field"><label>??</label><input id="mpo"></div></div><button class="btn" onclick="saveMember()">??</button> <button class="btn secondary" onclick="closeModal()">??</button>`)}function saveMember(){api('/members',{method:'POST',body:JSON.stringify({name:mn.value,stuno:ms.value,bm:mb.value,posts:mpo.value})}).then(()=>{closeModal();loadMembers()})}
function loadOrg(){api('/organization/summary').then(d=>{let by={};(d.members||[]).forEach(m=>{let k=m.department_id||'none';(by[k]||(by[k]=[])).push(m)});content.innerHTML=`<div class="section-title"><h3>???</h3>${has('organization.manage')||has('*')?'<button class="btn" onclick="openDeptForm()">????</button>':''}</div><div class="org-grid">${(d.departments||[]).map(dep=>`<div class="dept"><h3>${esc(dep.name)}</h3><p><span class="pill">? ${dep.member_count}</span> <span class="pill ok">?? ${dep.active_count||0}</span></p><div class="people">${(by[dep.id]||[]).slice(0,18).map(m=>`<span class="person" onclick="viewMember(${m.id})">${esc(m.name)} ? ${esc(m.posts)}</span>`).join('')||'<span class="label">????</span>'}</div></div>`).join('')}</div>`})}function openDeptForm(){modal(`<h3>????</h3><div class="field"><label>????</label><input id="dn"></div><button class="btn" onclick="api('/departments',{method:'POST',body:JSON.stringify({name:dn.value})}).then(()=>{closeModal();loadOrg()})">??</button> <button class="btn secondary" onclick="closeModal()">??</button>`)}
function loadEval(){Promise.all([api('/evaluations'),api('/evaluations/summary'),api('/members?status=active&limit=100')]).then(([e,s,m])=>{state.members=m.data||[];content.innerHTML=`<div class="section-title"><h3>????</h3>${has('evaluations.manage')||has('*')?'<button class="btn" onclick="openEvalForm()">????</button>':''}</div><div class="grid2"><div class="card"><h3>???????</h3>${(s.data||[]).map(x=>`<p>${esc(x.department)} <span class="pill">?? ${x.evaluated}</span> <span class="pill ok">?? ${x.avg_score||0}</span></p><div class="score"><span style="width:${Math.min(100,x.avg_score||0)}%"></span></div>`).join('')}</div><div class="card"><h3>????</h3><p>?????????????????????? 25 ?????????????????????????</p></div></div><div class="table-wrap" style="margin-top:16px"><table><thead><tr><th>??</th><th>??</th><th>??</th><th>??</th><th>??</th><th>???</th><th>??</th></tr></thead><tbody>${(e.data||[]).map(x=>`<tr><td>${esc(x.member_name)}</td><td>${esc(x.bm)}</td><td>${esc(x.posts)}</td><td>${x.total_score}</td><td><span class="pill ok">${esc(x.level)}</span></td><td>${esc(x.evaluator)}</td><td>${x.created_at}</td></tr>`).join('')}</tbody></table></div>`})}function openEvalForm(){modal(`<h3>??????</h3><div class="field"><label>??</label><select id="em">${state.members.map(m=>`<option value="${m.id}">${esc(m.name)} - ${esc(m.stuno)} - ${esc(m.bm)}</option>`).join('')}</select></div><div class="form-grid"><div class="field"><label>????</label><input id="s1" type="number" value="22"></div><div class="field"><label>????</label><input id="s2" type="number" value="22"></div><div class="field"><label>????</label><input id="s3" type="number" value="22"></div><div class="field"><label>????</label><input id="s4" type="number" value="22"></div></div><div class="field"><label>??</label><textarea id="ec"></textarea></div><button class="btn" onclick="api('/evaluations',{method:'POST',body:JSON.stringify({member_id:em.value,work_score:s1.value,discipline_score:s2.value,collaboration_score:s3.value,growth_score:s4.value,comment:ec.value})}).then(()=>{closeModal();loadEval()})">??</button> <button class="btn secondary" onclick="closeModal()">??</button>`)}
function loadPerm(){Promise.all([api('/members?status=active&limit=100'),api('/permissions/catalog')]).then(([m,p])=>{content.innerHTML=`<div class="card"><h3>????</h3><p>??????????????????????????????????</p><div class="form-grid"><div class="field"><label>??</label><select id="pm">${(m.data||[]).map(x=>`<option value="${x.id}">${esc(x.name)} - ${esc(x.bm)} - ${esc(x.posts)}</option>`).join('')}</select></div><div class="field"><label>??</label><select id="pp">${(p.data||[]).map(x=>`<option>${x}</option>`).join('')}</select></div></div><button class="btn" onclick="api('/permissions/grant',{method:'POST',body:JSON.stringify({member_id:pm.value,permission:pp.value,effect:'allow',scope_type:'global'})}).then(()=>alert('????'))">??</button></div>`})}
function loadApprovals(){api('/approvals').then(d=>{content.innerHTML=`<div class="table-wrap"><table><thead><tr><th>??</th><th>??</th><th>???</th><th>??</th><th>??</th></tr></thead><tbody>${(d.data||[]).map(x=>`<tr><td>${esc(x.title)}</td><td>${esc(x.type)}</td><td>${esc(x.applicant_stuno)}</td><td><span class="pill">${x.status}</span></td><td>${x.created_at}</td></tr>`).join('')}</tbody></table></div>`})}function loadImports(){content.innerHTML=`<div class="card"><h3>????</h3><p>?? CSV / XLS / XLSX??????????????????????????????</p><input type="file" id="file"><button class="btn" onclick="previewImport()">????</button><pre id="importResult"></pre></div>`}function previewImport(){let fd=new FormData();fd.append('file',file.files[0]);fetch('/DepartmentIFO/member-platform/api/imports/preview',{method:'POST',headers:{'Authorization':'Bearer '+token},body:fd}).then(r=>r.json()).then(d=>importResult.textContent=JSON.stringify(d,null,2))}function loadAudit(){api('/audit-logs').then(d=>{content.innerHTML=`<div class="table-wrap"><table><thead><tr><th>???</th><th>??</th><th>??</th><th>??</th><th>??</th></tr></thead><tbody>${(d.data||[]).map(x=>`<tr><td>${esc(x.actor)}</td><td>${esc(x.action)}</td><td>${esc(x.target_type)} #${esc(x.target_id)}</td><td>${esc(x.detail)}</td><td>${x.created_at}</td></tr>`).join('')}</tbody></table></div>`})}
function modal(html){modalCard.innerHTML=html;document.getElementById('modal').classList.add('show')}function closeModal(){document.getElementById('modal').classList.remove('show')}if(token)boot();else renderLogin();
</script></body></html>
